+#[test]
+fn screen_contract_accepts_scrollback_filled_viewport() {
+    let mut report = ResizeInvariantReport::new();
+    let snap = ScreenSnapshot {
+        lines_len: 24 + 1000, // exactly at capacity
+        ..valid_screen()
+    };
+    check_screen_invariants(&mut report, Some(9), &snap);
+    assert!(
